            let mut m = indexmap::IndexMap::new();
                m.insert("id".to_string(), requestId.clone());
                m.insert("messageHash".to_string(), messageHash.clone());
                m.insert("symbol".to_string(), symbol.clone());
                m.insert("params".to_string(), params.clone());
